+    let introspection = connector
+        .handle_introspect()
+        .await
+        .expect("introspect should succeed");
+
+    let operations = introspection["operations"].as_array().unwrap();
+    // 6 original + 3 new = 9 operations
+    assert_eq!(
+        operations.len(),
+        9,
+        "expected 9 operations, got {}: {:?}",
+        operations.len(),
+        operations
+            .iter()
+            .map(|o| o["id"].as_str().unwrap_or("?"))
+            .collect::<Vec<_>>()
